INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Gestion des projets', 'Formation sur les fondamentaux de la gestion de projets pour planifier, organiser et piloter efficacement.', 5, 150.00, 'entreprise', '2026-02-05', 30, '2026-01-14 12:37:32', '2026-01-14 12:37:32', NULL, E'--- OBJECTIFS ---\n• Comprendre les principes de la gestion de projets\n• Maîtriser les étapes clés : planification, exécution et suivi\n• Utiliser des outils et méthodes pour organiser efficacement\n• Développer des compétences en communication et coordination\n• Optimiser la performance et atteindre les objectifs fixés\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants aux fondamentaux de la gestion de projets, leur apprendre à planifier, organiser et piloter efficacement, utiliser des outils adaptés et développer des compétences de communication et coordination.\n\n--- PRÉREQUIS ---\nAucune connaissance préalable requise. Une familiarité avec le travail en équipe est recommandée.\n\n--- CONTENU ---\nModule 1 : Introduction à la gestion de projets\nModule 2 : Définition des objectifs et planification\nModule 3 : Organisation et répartition des tâches\nModule 4 : Suivi et contrôle de l’avancement\nModule 5 : Communication et coordination d’équipe\nModule 6 : Gestion des risques et résolution de problèmes\nModule 7 : Atelier pratique – Élaboration d’un plan de projet\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nChefs de projet débutants, managers, responsables d’équipe, étudiants et toute personne souhaitant acquérir des compétences en gestion de projets.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, études de cas, ateliers pratiques et exercices guidés.\n\n--- SUPPORTS ---\nLogiciels de gestion de projets (ex. Trello, MS Project), modèles de planification, supports PDF, slides et tutoriels pratiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
